module verified_decoder_2to4(in, decoded_value);  

    input  [1:0] in;  
    output  [3:0] decoded_value;  
    reg   [3:0]  decoded_value; 

    always @(in)
          begin
            case(in)
                2'b00: decoded_value = 4'b0001;
                2'b01: decoded_value = 4'b0010;
                2'b10: decoded_value = 4'b0100;
                2'b11: decoded_value = 4'b1000;
                default: decoded_value = 4'b0000;
            endcase
          end  

endmodule
